-- 038: Seed olympiad data
-- 54 олимпиады (9 на каждую категорию) и 540 вопросов (10 на каждую олимпиаду)
-- Категории: pedagogues_dou, pedagogues_school, pedagogues_ovz, students, preschoolers, logopedists
-- Все вопросы лёгкие — бизнес-модель предполагает, что большинство участников набирают 9-10 из 10

SET NAMES utf8mb4;
SET CHARACTER SET utf8mb4;

-- ============================================================
-- КАТЕГОРИЯ 1: ПЕДАГОГИ ДОУ (pedagogues_dou) — 9 олимпиад
-- Темы: ФГОС ДО (3), Развивающая предметно-пространственная среда (3), Игровая деятельность (3)
-- ============================================================

-- Олимпиада 1
VALUES ('Олимпиада: Основы ФГОС ДО', 'olimpiada-osnovy-fgos-do',
'Проверьте знания основных положений Федерального государственного образовательного стандарта дошкольного образования.',
'<p><strong>Всероссийская олимпиада «Основы ФГОС ДО»</strong> — это профессиональное онлайн-тестирование для педагогов дошкольного образования, которые хотят подтвердить знание Федерального государственного образовательного стандарта. ФГОС ДО является фундаментом современного дошкольного образования, и уверенное владение его положениями — обязательное условие успешной работы воспитателя.</p><h3>Что вас ждёт</h3><p>Олимпиада включает 10 вопросов по ключевым разделам ФГОС ДО: целевые ориентиры, пять образовательных областей, принципы индивидуализации, требования к структуре образовательной программы ДОУ. Вы проверите, насколько хорошо понимаете основы стандарта, которым руководствуетесь ежедневно.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям дошкольных образовательных учреждений</li><li>Старшим воспитателям и методистам ДОУ</li><li>Студентам педагогических колледжей и вузов</li><li>Педагогам, готовящимся к аттестации</li></ul><h3>Преимущества участия</h3><ul><li>Участие <strong>полностью бесплатное</strong> — проходите тест в удобное время</li><li>Диплом I, II или III степени для портфолио при аттестации — 169 руб.</li><li>Систематизация знаний по ФГОС ДО в формате экспресс-проверки</li><li>Подтверждение профессиональной компетенции на всероссийском уровне</li></ul>',
'pedagogues_dou', 'ФГОС ДО', NULL, 169.00, 1, 1);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 2
VALUES ('Олимпиада: Реализация ФГОС ДО в практике воспитателя', 'olimpiada-realizatsiya-fgos-do-v-praktike',
'Олимпиада о практическом применении требований ФГОС ДО в ежедневной работе воспитателя.',
'<p><strong>Олимпиада «Реализация ФГОС ДО в практике воспитателя»</strong> — это онлайн-тестирование, посвящённое практическому применению стандарта в ежедневной работе. Если вы хотите убедиться, что правильно внедряете требования ФГОС ДО в образовательный процесс, эта олимпиада — для вас.</p><h3>Что вас ждёт</h3><p>10 вопросов о реальной педагогической практике: календарно-тематическое планирование, индивидуальные образовательные маршруты, формы работы с родителями, мониторинг развития ребёнка, системно-деятельностный подход и организация развивающей среды по ФГОС ДО.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям ДОУ, ежедневно реализующим ФГОС ДО</li><li>Педагогам, проходящим аттестацию на категорию</li><li>Методистам и старшим воспитателям</li><li>Начинающим специалистам дошкольного образования</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> без ограничений по времени</li><li>Практико-ориентированные вопросы из реальной работы воспитателя</li><li>Диплом всероссийского уровня для профессионального портфолио — 169 руб.</li><li>Возможность выявить пробелы в практическом применении стандарта</li></ul>',
'pedagogues_dou', 'ФГОС ДО', NULL, 169.00, 1, 2);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 3
VALUES ('Олимпиада: Образовательные области ФГОС ДО', 'olimpiada-obrazovatelnye-oblasti-fgos-do',
'Проверьте знания пяти образовательных областей ФГОС дошкольного образования.',
'<p><strong>Олимпиада «Образовательные области ФГОС ДО»</strong> — углублённое онлайн-тестирование по пяти образовательным областям дошкольного стандарта. Знаете ли вы, к какой области относится каждая задача развития ребёнка? Эта олимпиада поможет проверить и укрепить ваши знания.</p><h3>Что вас ждёт</h3><p>10 вопросов о содержании пяти образовательных областей ФГОС ДО: познавательное развитие, речевое развитие, социально-коммуникативное развитие, художественно-эстетическое развитие и физическое развитие. Вопросы проверяют умение соотносить конкретные задачи и виды деятельности с соответствующей областью.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям, планирующим работу по образовательным областям</li><li>Музыкальным руководителям и инструкторам по физкультуре</li><li>Педагогам, разрабатывающим рабочие программы ДОУ</li><li>Студентам педагогических специальностей</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> — без регистрационных взносов</li><li>Глубокая проверка знаний содержания каждой образовательной области</li><li>Диплом победителя для аттестационного портфолио — 169 руб.</li><li>Уверенность в правильном планировании образовательной деятельности</li></ul>',
'pedagogues_dou', 'ФГОС ДО', NULL, 169.00, 1, 3);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 4
VALUES ('Олимпиада: Организация РППС в ДОУ', 'olimpiada-organizatsiya-rpps-v-dou',
'Олимпиада по основам организации развивающей предметно-пространственной среды в дошкольном учреждении.',
'<p><strong>Всероссийская олимпиада «Организация РППС в ДОУ»</strong> — онлайн-тестирование для воспитателей, посвящённое основам создания развивающей предметно-пространственной среды в детском саду. РППС — один из ключевых инструментов педагога: правильно организованная среда становится «третьим воспитателем» для ребёнка.</p><h3>Что вас ждёт</h3><p>10 вопросов о принципах РППС по ФГОС ДО: содержательная насыщенность, трансформируемость, полифункциональность, вариативность, доступность и безопасность. Вы проверите знания о том, как создать среду, стимулирующую познание, творчество и самостоятельность дошкольников.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям, оформляющим групповое пространство</li><li>Старшим воспитателям, контролирующим качество РППС</li><li>Заведующим и методистам дошкольных учреждений</li><li>Педагогам, готовящим портфолио для аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> — пройдите тест в любое удобное время</li><li>Проверка практических знаний по организации среды в группе</li><li>Диплом всероссийской олимпиады для портфолио — 169 руб.</li><li>Уверенность при проверках и оценке качества РППС</li></ul>',
'pedagogues_dou', 'Развивающая предметно-пространственная среда', NULL, 169.00, 1, 4);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 5
VALUES ('Олимпиада: Центры активности и зонирование в ДОУ', 'olimpiada-tsentry-aktivnosti-zonirovanie-dou',
'Проверьте знания о зонировании группового пространства и организации центров активности.',
'<p><strong>Олимпиада «Центры активности и зонирование в ДОУ»</strong> — тестирование для воспитателей, которые хотят проверить знания о грамотном разделении группового пространства на функциональные зоны. Правильное зонирование помогает каждому ребёнку найти занятие по интересам и развиваться в комфортной обстановке.</p><h3>Что вас ждёт</h3><p>10 вопросов о практике зонирования: центр сюжетно-ролевой игры, книжный уголок, центр экспериментирования, уголок уединения, музыкальный уголок и центр конструирования. Вы проверите, как организовать пространство для разных видов детской активности.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям всех возрастных групп ДОУ</li><li>Педагогам, обновляющим предметную среду группы</li><li>Специалистам по дизайну образовательного пространства</li><li>Студентам педагогических факультетов</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное прохождение</strong> олимпиады из 10 вопросов</li><li>Практические знания о современных подходах к зонированию</li><li>Диплом I, II или III степени для профессионального портфолио — 169 руб.</li><li>Идеи для улучшения РППС в вашей группе</li></ul>',
'pedagogues_dou', 'Развивающая предметно-пространственная среда', NULL, 169.00, 1, 5);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 6
VALUES ('Олимпиада: Современные подходы к РППС', 'olimpiada-sovremennye-podkhody-rpps',
'Олимпиада о современных тенденциях и инновациях в создании развивающей среды.',
'<p><strong>Олимпиада «Современные подходы к РППС»</strong> — тестирование для педагогов, интересующихся инновационными решениями в организации развивающей среды. Лэпбуки, бизиборды, интерактивные стены, макетирование — современная РППС выходит далеко за рамки стандартного набора игрушек.</p><h3>Что вас ждёт</h3><p>10 вопросов о передовых подходах к РППС: концепция «говорящей среды», использование природных материалов, полифункциональное оборудование, принцип динамичности и исследовательский подход к организации пространства группы.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям, стремящимся к инновациям в оформлении группы</li><li>Методистам, внедряющим новые стандарты РППС</li><li>Педагогам, участвующим в конкурсах профмастерства</li><li>Специалистам ДОУ, повышающим квалификацию</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие бесплатное</strong> — тест доступен в любое время</li><li>Актуальные вопросы о трендах развивающей среды</li><li>Диплом для аттестационного портфолио педагога — 169 руб.</li><li>Новые идеи для обогащения среды в вашей группе</li></ul>',
'pedagogues_dou', 'Развивающая предметно-пространственная среда', NULL, 169.00, 1, 6);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 7
VALUES ('Олимпиада: Игровые технологии в ДОУ', 'olimpiada-igrovye-tekhnologii-v-dou',
'Проверьте знания об использовании игровых технологий в образовательном процессе детского сада.',
'<p><strong>Всероссийская олимпиада «Игровые технологии в ДОУ»</strong> — профессиональное онлайн-тестирование для воспитателей, которые используют игру как главный инструмент развития дошкольника. Игровая деятельность — ведущая в дошкольном возрасте, и грамотное применение игровых технологий определяет качество образовательного процесса.</p><h3>Что вас ждёт</h3><p>10 вопросов о классификации и методике игровых технологий: сюжетно-ролевые, дидактические, театрализованные, строительно-конструктивные и подвижные игры. Вопросы затрагивают теоретические основы (Л.С. Выготский, Д.Б. Эльконин) и практику руководства игрой.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям всех возрастных групп ДОУ</li><li>Педагогам дополнительного образования в детском саду</li><li>Музыкальным руководителям и инструкторам по физкультуре</li><li>Специалистам, готовящимся к аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Полностью бесплатное участие</strong> — без регистрационных сборов</li><li>Проверка знаний по всем видам игровой деятельности</li><li>Диплом I, II или III степени для портфолио — 169 руб.</li><li>Уверенное владение теорией и практикой игровых технологий</li></ul>',
'pedagogues_dou', 'Игровая деятельность', NULL, 169.00, 1, 7);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 8
VALUES ('Олимпиада: Сюжетно-ролевая игра в ДОУ', 'olimpiada-syuzhetno-rolevaya-igra-v-dou',
'Олимпиада о теории и практике сюжетно-ролевых игр в дошкольном учреждении.',
'<p><strong>Олимпиада «Сюжетно-ролевая игра в ДОУ»</strong> — специализированное тестирование для воспитателей, посвящённое главному виду игровой деятельности дошкольников. Сюжетно-ролевая игра развивает воображение, коммуникативные навыки и социальный опыт ребёнка — и педагог должен уметь её грамотно сопровождать.</p><h3>Что вас ждёт</h3><p>10 вопросов о теории и практике сюжетно-ролевой игры: структура (сюжет, роль, игровые действия), возрастные особенности, способы обогащения игрового опыта, предметы-заместители и позиция воспитателя как партнёра в игре.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям, организующим игровую деятельность в группе</li><li>Педагогам-психологам детских садов</li><li>Молодым специалистам дошкольного образования</li><li>Педагогам, собирающим портфолио для аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> — пройдите тест онлайн в удобное время</li><li>Углублённые вопросы по ведущему виду деятельности дошкольника</li><li>Диплом победителя всероссийской олимпиады — 169 руб.</li><li>Практические знания для ежедневной работы с детьми</li></ul>',
'pedagogues_dou', 'Игровая деятельность', NULL, 169.00, 1, 8);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 9
VALUES ('Олимпиада: Дидактические игры в дошкольном образовании', 'olimpiada-didakticheskie-igry-doshkolnoe',
'Олимпиада по использованию дидактических игр как средства обучения и развития дошкольников.',
'<p><strong>Олимпиада «Дидактические игры в дошкольном образовании»</strong> — тестирование для педагогов, которые используют дидактическую игру как эффективный инструмент обучения. Дидактическая игра объединяет учебную задачу и игровую форму, позволяя ребёнку осваивать новые знания с удовольствием.</p><h3>Что вас ждёт</h3><p>10 вопросов о дидактических играх: структура (задача, правила, игровое действие), виды (предметные, настольно-печатные, словесные), подбор игр по возрасту, роль воспитателя в организации и руководстве, сенсорные игры и принцип постепенного усложнения.</p><h3>Кому подойдёт</h3><ul><li>Воспитателям, активно применяющим дидактические игры</li><li>Педагогам, разрабатывающим авторские обучающие игры</li><li>Учителям-дефектологам и логопедам ДОУ</li><li>Студентам дошкольного и начального образования</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие бесплатное</strong> — без регистрационных сборов</li><li>Проверка методической грамотности в организации дидактических игр</li><li>Диплом для аттестационного портфолио — 169 руб.</li><li>Систематизация знаний о структуре и видах дидактических игр</li></ul>',
'pedagogues_dou', 'Игровая деятельность', NULL, 169.00, 1, 9);
SET @olympiad_id = LAST_INSERT_ID();


