VALUES ('Олимпиада: Современные методики преподавания', 'olimpiada-sovremennye-metodiki-prepodavaniya',
'Проверьте знания о современных методах и приёмах преподавания в школе.',
'<p><strong>Всероссийская олимпиада «Современные методики преподавания»</strong> — профессиональное онлайн-тестирование для учителей, владеющих актуальными подходами к обучению. Современная школа требует от педагога не просто передачи знаний, а создания условий для активного познания и развития каждого ученика.</p><h3>Что вас ждёт</h3><p>10 вопросов о ключевых методиках: системно-деятельностный подход, проблемное обучение, метод проектов, дифференцированный подход, формирующее оценивание, технологическая карта урока и рефлексия. Вы проверите, насколько уверенно применяете современные педагогические технологии.</p><h3>Кому подойдёт</h3><ul><li>Учителям-предметникам начальной и средней школы</li><li>Молодым педагогам, осваивающим профессию</li><li>Учителям, проходящим аттестацию на категорию</li><li>Студентам педагогических вузов и колледжей</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> — пройдите тест онлайн без ограничений</li><li>Актуальные вопросы по методике преподавания по ФГОС</li><li>Диплом всероссийского уровня для аттестационного портфолио — 169 руб.</li><li>Систематизация знаний о современных педагогических подходах</li></ul>',
'pedagogues_school', 'Методика преподавания', NULL, 169.00, 1, 10);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 11
VALUES ('Олимпиада: Активные методы обучения в школе', 'olimpiada-aktivnye-metody-obucheniya',
'Олимпиада об использовании активных и интерактивных методов в школьном образовании.',
'<p><strong>Олимпиада «Активные методы обучения в школе»</strong> — тестирование для педагогов, использующих интерактивные технологии вовлечения учеников. Мозговой штурм, кейс-метод, дискуссия, перевёрнутый класс — активные методы превращают ученика из пассивного слушателя в участника образовательного процесса.</p><h3>Что вас ждёт</h3><p>10 вопросов о практике активного обучения: методы генерации идей, ролевые игры, технология «перевёрнутый класс», ментальные карты, работа в парах и группах, интерактивное обучение и его отличие от традиционного.</p><h3>Кому подойдёт</h3><ul><li>Учителям, стремящимся повысить вовлечённость учеников</li><li>Педагогам, внедряющим интерактивные технологии</li><li>Классным руководителям и тьюторам</li><li>Методистам и наставникам молодых специалистов</li></ul><h3>Преимущества участия</h3><ul><li><strong>Полностью бесплатное</strong> онлайн-тестирование</li><li>Практико-ориентированные вопросы из школьной практики</li><li>Диплом для портфолио и аттестации — 169 руб.</li><li>Проверка владения современными интерактивными технологиями</li></ul>',
'pedagogues_school', 'Методика преподавания', NULL, 169.00, 1, 11);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 12
VALUES ('Олимпиада: Оценивание и контроль в образовании', 'olimpiada-otsenivanie-i-kontrol-v-obrazovanii',
'Олимпиада о современных подходах к оцениванию и контролю учебных достижений школьников.',
'<p><strong>Олимпиада «Оценивание и контроль в образовании»</strong> — онлайн-тестирование для учителей, которые хотят проверить знания о современных системах оценивания. Формирующее и суммативное оценивание, критериальный подход, самооценка и взаимооценивание — грамотная система контроля мотивирует ученика, а не пугает.</p><h3>Что вас ждёт</h3><p>10 вопросов о системе оценивания: отличие формирующего оценивания от итогового, портфолио ученика, критериальный подход, самооценка, взаимооценивание, диагностические работы, обратная связь и безотметочное обучение.</p><h3>Кому подойдёт</h3><ul><li>Учителям-предметникам всех ступеней образования</li><li>Педагогам, внедряющим критериальное оценивание</li><li>Завучам по учебной работе</li><li>Учителям, готовящимся к аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> без ограничений по времени</li><li>Углублённые вопросы о современных подходах к оцениванию</li><li>Диплом победителя для профессионального портфолио — 169 руб.</li><li>Возможность пересмотреть и улучшить свою систему оценивания</li></ul>',
'pedagogues_school', 'Методика преподавания', NULL, 169.00, 1, 12);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 13
VALUES ('Олимпиада: Воспитательная работа в школе', 'olimpiada-vospitatelnaya-rabota-v-shkole',
'Олимпиада по основам организации воспитательной работы в общеобразовательной школе.',
'<p><strong>Всероссийская олимпиада «Воспитательная работа в школе»</strong> — тестирование для педагогов, отвечающих за духовно-нравственное, патриотическое и социальное воспитание учеников. Воспитательная работа — неотъемлемая часть образовательного процесса, и её качество напрямую влияет на формирование личности школьника.</p><h3>Что вас ждёт</h3><p>10 вопросов о направлениях и формах воспитательной работы: программа воспитания, классные часы, патриотическое и духовно-нравственное воспитание, профилактика буллинга, ученическое самоуправление, экологическое и трудовое воспитание, взаимодействие с семьёй.</p><h3>Кому подойдёт</h3><ul><li>Классным руководителям всех параллелей</li><li>Заместителям директора по воспитательной работе</li><li>Педагогам-организаторам и социальным педагогам</li><li>Учителям, формирующим портфолио для аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие полностью бесплатное</strong> — без регистрационных сборов</li><li>Вопросы охватывают все направления воспитательной работы</li><li>Диплом I, II или III степени для портфолио — 169 руб.</li><li>Подтверждение компетенций в области воспитания и социализации</li></ul>',
'pedagogues_school', 'Воспитательная работа', NULL, 169.00, 1, 13);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 14
VALUES ('Олимпиада: Работа классного руководителя', 'olimpiada-rabota-klassnogo-rukovoditelya',
'Олимпиада о функциях, задачах и методах работы классного руководителя.',
'<p><strong>Олимпиада «Работа классного руководителя»</strong> — специализированное тестирование для педагогов, выполняющих роль классного руководителя. Вы — связующее звено между учениками, родителями и школой. Эта олимпиада поможет проверить, насколько уверенно вы владеете инструментами классного руководства.</p><h3>Что вас ждёт</h3><p>10 вопросов о практике классного руководителя: планирование воспитательной работы, родительские собрания, индивидуальные беседы, формирование классного коллектива, диагностика, разрешение конфликтов, традиции класса и взаимодействие со школьными специалистами.</p><h3>Кому подойдёт</h3><ul><li>Действующим классным руководителям</li><li>Учителям, впервые принимающим классное руководство</li><li>Педагогам-психологам и социальным педагогам</li><li>Специалистам, проходящим аттестацию</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное прохождение</strong> теста из 10 вопросов</li><li>Практические вопросы из реальной работы классного руководителя</li><li>Диплом для профессионального портфолио — 169 руб.</li><li>Системная проверка навыков организации воспитательного процесса</li></ul>',
'pedagogues_school', 'Воспитательная работа', NULL, 169.00, 1, 14);
SET @olympiad_id = LAST_INSERT_ID();


