VALUES ('Олимпиада: Профилактика и безопасность в школе', 'olimpiada-profilaktika-bezopasnost-v-shkole',
'Олимпиада о профилактической работе и обеспечении безопасности в школьной среде.',
'<p><strong>Олимпиада «Профилактика и безопасность в школе»</strong> — тестирование для педагогов, отвечающих за безопасную образовательную среду. Профилактика девиантного поведения, кибербезопасность, антитеррористическая защита и здоровьесбережение — знания, которые могут спасти жизнь и здоровье ваших учеников.</p><h3>Что вас ждёт</h3><p>10 вопросов о безопасности в школе: профилактика девиантного поведения и употребления ПАВ, кибербезопасность, школьная медиация, дети группы риска, пожарная и антитеррористическая безопасность, профилактика суицидального поведения, здоровьесберегающие технологии.</p><h3>Кому подойдёт</h3><ul><li>Классным руководителям и педагогам-организаторам</li><li>Социальным педагогам и педагогам-психологам</li><li>Заместителям директора по безопасности</li><li>Всем педагогам, работающим с подростками</li></ul><h3>Преимущества участия</h3><ul><li><strong>Полностью бесплатное участие</strong> в онлайн-формате</li><li>Проверка знаний по актуальным вопросам школьной безопасности</li><li>Диплом всероссийской олимпиады для портфолио — 169 руб.</li><li>Уверенность в готовности к профилактической работе</li></ul>',
'pedagogues_school', 'Воспитательная работа', NULL, 169.00, 1, 15);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 16
VALUES ('Олимпиада: Цифровые технологии на уроке', 'olimpiada-tsifrovye-tekhnologii-na-uroke',
'Олимпиада об использовании цифровых инструментов в преподавании школьных предметов.',
'<p><strong>Всероссийская олимпиада «Цифровые технологии на уроке»</strong> — онлайн-тестирование для учителей, использующих ИКТ в образовательном процессе. Интерактивные доски, образовательные платформы, электронные ресурсы — цифровые инструменты открывают новые возможности для эффективного преподавания.</p><h3>Что вас ждёт</h3><p>10 вопросов об ИКТ-компетентности педагога: использование интерактивных досок, электронных дневников, образовательных платформ, презентаций, ЭОР, онлайн-тестирования. Вопросы затрагивают санитарные нормы и цифровую грамотность учеников.</p><h3>Кому подойдёт</h3><ul><li>Учителям-предметникам, активно использующим ИКТ</li><li>Педагогам, осваивающим цифровые образовательные ресурсы</li><li>Учителям информатики и технологии</li><li>Педагогам, подтверждающим ИКТ-компетентность для аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие бесплатное</strong> — без регистрационных взносов</li><li>Подтверждение владения цифровыми образовательными инструментами</li><li>Диплом для аттестационного портфолио — 169 руб.</li><li>Соответствие требованиям профстандарта педагога к ИКТ-компетенции</li></ul>',
'pedagogues_school', 'Цифровые технологии в образовании', NULL, 169.00, 1, 16);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 17
VALUES ('Олимпиада: Дистанционное и смешанное обучение', 'olimpiada-distantsionnoe-smeshannoe-obuchenie',
'Олимпиада о технологиях дистанционного и смешанного обучения в школе.',
'<p><strong>Олимпиада «Дистанционное и смешанное обучение»</strong> — тестирование для педагогов, которые проводят уроки в онлайн и гибридном формате. Смешанное обучение стало реальностью современной школы, и умение организовать эффективный дистанционный урок — ключевая компетенция учителя.</p><h3>Что вас ждёт</h3><p>10 вопросов о дистанционных и смешанных технологиях: модели смешанного обучения (ротация станций), видеоконференции, синхронное и асинхронное обучение, LMS-платформы, электронное портфолио, мотивация на расстоянии и цифровая этика.</p><h3>Кому подойдёт</h3><ul><li>Учителям, проводящим уроки в дистанционном формате</li><li>Педагогам, внедряющим смешанное обучение</li><li>Методистам, курирующим онлайн-образование</li><li>Учителям, повышающим квалификацию в области EdTech</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное прохождение</strong> олимпиады из 10 вопросов</li><li>Актуальные вопросы о технологиях онлайн-преподавания</li><li>Диплом I, II или III степени для портфолио — 169 руб.</li><li>Подтверждение готовности работать в любом формате обучения</li></ul>',
'pedagogues_school', 'Цифровые технологии в образовании', NULL, 169.00, 1, 17);
