VALUES ('Олимпиада: Основы инклюзивного образования', 'olimpiada-osnovy-inklyuzivnogo-obrazovaniya',
'Проверьте знания об основных принципах и подходах инклюзивного образования.',
'<p><strong>Всероссийская олимпиада «Основы инклюзивного образования»</strong> — профессиональное онлайн-тестирование для педагогов, работающих с детьми с ограниченными возможностями здоровья. Инклюзивное образование — право каждого ребёнка, закреплённое в ФЗ-273, и педагог должен знать его принципы и механизмы реализации.</p><h3>Что вас ждёт</h3><p>10 вопросов об основах инклюзии: понятие и принципы инклюзивного образования, закон 273-ФЗ, роль ПМПК, адаптированные программы (АООП), тьюторское сопровождение, безбарьерная среда и специальные образовательные условия для детей с ОВЗ.</p><h3>Кому подойдёт</h3><ul><li>Педагогам школ и ДОУ, работающим в инклюзивных классах</li><li>Учителям-дефектологам и тьюторам</li><li>Заместителям директора по учебной работе</li><li>Студентам дефектологических и педагогических факультетов</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие полностью бесплатное</strong> — без ограничений по времени</li><li>Проверка знаний законодательных основ инклюзии</li><li>Диплом всероссийской олимпиады для портфолио — 169 руб.</li><li>Подтверждение компетенций для работы с детьми с ОВЗ</li></ul>',
'pedagogues_ovz', 'Инклюзивное образование', NULL, 169.00, 1, 19);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 20
VALUES ('Олимпиада: Организация инклюзивного обучения', 'olimpiada-organizatsiya-inklyuzivnogo-obucheniya',
'Олимпиада о практических аспектах организации инклюзивного обучения в школе и ДОУ.',
'<p><strong>Олимпиада «Организация инклюзивного обучения»</strong> — тестирование для педагогов, которые на практике создают инклюзивную образовательную среду. От адаптации учебного материала до командного взаимодействия специалистов — олимпиада проверяет реальные навыки организации инклюзивного процесса.</p><h3>Что вас ждёт</h3><p>10 вопросов о практике инклюзии: адаптация учебного материала, психолого-педагогический консилиум, ассистивные технологии, сенсорная комната, визуальное расписание для детей с РАС, дифференцированные задания, формирование толерантности и командная работа специалистов.</p><h3>Кому подойдёт</h3><ul><li>Учителям инклюзивных классов и групп</li><li>Тьюторам и ассистентам педагогов</li><li>Педагогам-психологам и дефектологам</li><li>Специалистам, проходящим курсы повышения квалификации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное прохождение</strong> теста из 10 вопросов</li><li>Практико-ориентированные вопросы из реальной инклюзивной практики</li><li>Диплом для аттестационного портфолио — 169 руб.</li><li>Систематизация навыков организации инклюзивного процесса</li></ul>',
'pedagogues_ovz', 'Инклюзивное образование', NULL, 169.00, 1, 20);
SET @olympiad_id = LAST_INSERT_ID();


