VALUES ('Олимпиада: Волшебный мир сказок', 'olimpiada-volshebnyy-mir-skazok',
'Олимпиада для дошкольников по любимым русским и мировым сказкам.',
'<p><strong>Всероссийская олимпиада «Волшебный мир сказок»</strong> — сказочная онлайн-викторина для дошкольников 5–7 лет. Колобок, Курочка Ряба, Буратино и другие любимые герои — ваш малыш покажет, как хорошо он знает русские народные и авторские сказки!</p><h3>Что ждёт малыша</h3><p>10 волшебных вопросов: герои сказок и их приключения, кто кого встретил на дорожке, какие слова произносил персонаж, чем закончилась сказка. Все вопросы по знакомым с детства произведениям — ребёнок с удовольствием вспомнит любимые истории.</p><h3>Кому подойдёт</h3><ul><li>Дошкольникам 5–7 лет, которые обожают сказки</li><li>Малышам, которым родители читают перед сном</li><li>Детям, готовящимся к школе и развивающим память</li></ul><h3>Что даёт участие</h3><ul><li><strong>Полностью бесплатное участие</strong> — проходите всей семьёй</li><li>Диплом для портфолио будущего школьника — 169 руб.</li><li>Развитие памяти, воображения и любви к чтению</li><li>Погружение в волшебный мир литературы</li></ul>',
'preschoolers', 'Творческое развитие', NULL, 169.00, 1, 42);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 43
VALUES ('Олимпиада: Весёлая азбука', 'olimpiada-vesyolaya-azbuka',
'Олимпиада для малышей о буквах, звуках и первых шагах в чтении.',
'<p><strong>Всероссийская олимпиада «Весёлая азбука»</strong> — онлайн-викторина для малышей 5–7 лет, знакомящихся с буквами русского алфавита. А, Б, В — ваш ребёнок покажет, как хорошо он знает буквы и какие слова начинаются на каждую из них!</p><h3>Что ждёт малыша</h3><p>10 простых и весёлых вопросов о буквах: с какой буквы начинается слово, какая буква пропущена, сколько букв в алфавите, чем отличаются гласные от согласных. Задания составлены для тех, кто только осваивает грамоту.</p><h3>Кому подойдёт</h3><ul><li>Дошкольникам 5–7 лет, изучающим буквы</li><li>Малышам, которые учатся читать с родителями</li><li>Детям, посещающим подготовительную группу ДОУ</li></ul><h3>Что даёт участие</h3><ul><li><strong>Участие бесплатное</strong> — проходите тест вместе с ребёнком</li><li>Диплом для портфолио будущего первоклассника — 169 руб.</li><li>Мотивация к изучению букв и обучению чтению</li><li>Первый шаг к грамотности в игровой форме</li></ul>',
'preschoolers', 'Развитие речи', NULL, 169.00, 1, 43);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 44
VALUES ('Олимпиада: Загадки и отгадки', 'olimpiada-zagadki-i-otgadki',
'Весёлая олимпиада-викторина с загадками для самых маленьких.',
'<p><strong>Всероссийская олимпиада «Загадки и отгадки»</strong> — увлекательная онлайн-викторина для дошкольников 5–7 лет, построенная на загадках. Загадки развивают мышление, воображение и речь ребёнка — а отгадывать их всегда весело и интересно!</p><h3>Что ждёт малыша</h3><p>10 занимательных загадок о животных, предметах быта, явлениях природы и знакомых вещах. Каждая загадка — маленькая головоломка, которую ребёнок с удовольствием разгадает. Все загадки подобраны по возрасту — не слишком лёгкие, но и не сложные.</p><h3>Кому подойдёт</h3><ul><li>Дошкольникам 5–7 лет, которые обожают отгадывать загадки</li><li>Малышам, развивающим образное мышление</li><li>Детям, которые готовятся к школе</li></ul><h3>Что даёт участие</h3><ul><li><strong>Бесплатное участие</strong> — без регистрационных взносов</li><li>Красивый диплом победителя — 169 руб.</li><li>Развитие смекалки, мышления и словарного запаса</li><li>Весёлый и полезный досуг для ребёнка</li></ul>',
'preschoolers', 'Развитие речи', NULL, 169.00, 1, 44);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 45
VALUES ('Олимпиада: Рассказы по картинкам', 'olimpiada-rasskazy-po-kartinkam',
'Олимпиада для дошкольников на развитие связной речи и воображения.',
'<p><strong>Всероссийская олимпиада «Рассказы по картинкам»</strong> — речевая онлайн-викторина для дошкольников 5–7 лет, развивающая умение понимать и описывать сюжеты. Ребёнок покажет, как хорошо он видит детали, понимает последовательность событий и может рассказать о том, что происходит на картинке.</p><h3>Что ждёт малыша</h3><p>10 вопросов на понимание сюжета: что произошло сначала, а что потом, кто главный герой, что он делает, какое время года на картинке. Задания развивают связную речь и логическое мышление в игровой форме.</p><h3>Кому подойдёт</h3><ul><li>Дошкольникам 5–7 лет, которые любят рассматривать картинки</li><li>Малышам, развивающим связную речь</li><li>Детям, которым нравится придумывать истории</li></ul><h3>Что даёт участие</h3><ul><li><strong>Полностью бесплатное участие</strong> — проходите всей семьёй</li><li>Диплом I, II или III степени — 169 руб.</li><li>Развитие речи, внимания и навыков описания</li><li>Отличная подготовка к школьным заданиям по развитию речи</li></ul>',
'preschoolers', 'Развитие речи', NULL, 169.00, 1, 45);
