-- Олимпиада 46
VALUES ('Олимпиада: Диагностика речевого развития', 'olimpiada-diagnostika-rechevogo-razvitiya',
'Проверьте знания основ логопедической диагностики речевого развития у детей.',
'<p><strong>Всероссийская олимпиада «Диагностика речевого развития»</strong> — профессиональное онлайн-тестирование для логопедов, специализирующихся на обследовании речи. Точная диагностика — основа эффективной коррекционной работы, и каждый логопед должен владеть всем арсеналом диагностических методов.</p><h3>Что вас ждёт</h3><p>10 вопросов о логопедической диагностике: этапы обследования речи, методы изучения звукопроизношения, фонематического слуха, лексико-грамматического строя и связной речи. Вопросы охватывают как теоретические основы, так и практику диагностической работы.</p><h3>Кому подойдёт</h3><ul><li>Учителям-логопедам ДОУ и школ</li><li>Логопедам коррекционных и реабилитационных центров</li><li>Студентам логопедических факультетов</li><li>Специалистам, готовящимся к аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие полностью бесплатное</strong> — без ограничений по времени</li><li>Проверка диагностических компетенций логопеда</li><li>Диплом всероссийской олимпиады для портфолио — 169 руб.</li><li>Систематизация знаний по методам логопедического обследования</li></ul>',
'logopedists', 'Диагностика речевого развития', NULL, 169.00, 1, 46);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 47
VALUES ('Олимпиада: Обследование звукопроизношения', 'olimpiada-obsledovanie-zvukoproiznosheniya',
'Олимпиада о методах и приёмах обследования звукопроизношения у детей.',
'<p><strong>Олимпиада «Обследование звукопроизношения»</strong> — специализированное тестирование для логопедов, проводящих диагностику нарушений звукопроизношения. Ротацизм, сигматизм, ламбдацизм — проверьте, насколько уверенно вы определяете виды и формы нарушений звуков речи.</p><h3>Что вас ждёт</h3><p>10 вопросов о диагностике звукопроизношения: обследование артикуляционного аппарата, классификация нарушений звуков (замены, пропуски, искажения), дифференциальная диагностика, анализ результатов обследования и определение структуры дефекта.</p><h3>Кому подойдёт</h3><ul><li>Логопедам, проводящим первичное обследование</li><li>Специалистам ПМПК и логопедических пунктов</li><li>Логопедам частной практики</li><li>Студентам дефектологических факультетов</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное прохождение</strong> теста из 10 вопросов</li><li>Углублённые вопросы по диагностике звукопроизношения</li><li>Диплом для аттестационного портфолио — 169 руб.</li><li>Повышение точности диагностической работы</li></ul>',
'logopedists', 'Обследование звукопроизношения', NULL, 169.00, 1, 47);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 48
VALUES ('Олимпиада: Диагностика письменной речи', 'olimpiada-diagnostika-pismennoj-rechi',
'Проверьте знания о методах диагностики нарушений чтения и письма у детей.',
'<p><strong>Олимпиада «Диагностика письменной речи»</strong> — тестирование для логопедов, работающих с нарушениями чтения и письма у школьников. Дисграфия и дислексия — распространённые проблемы, и их своевременная диагностика определяет успех коррекционной работы.</p><h3>Что вас ждёт</h3><p>10 вопросов о диагностике письменной речи: виды дисграфии (акустическая, оптическая, аграмматическая), формы дислексии, методы обследования письма и чтения, анализ ошибок, определение механизмов нарушений и составление логопедического заключения.</p><h3>Кому подойдёт</h3><ul><li>Школьным логопедам и логопедам логопунктов</li><li>Специалистам, работающим с младшими школьниками</li><li>Логопедам коррекционных классов</li><li>Педагогам, проходящим аттестацию</li></ul><h3>Преимущества участия</h3><ul><li><strong>Полностью бесплатное участие</strong> в онлайн-формате</li><li>Проверка знаний по актуальной теме нарушений письменной речи</li><li>Диплом победителя для профессионального портфолио — 169 руб.</li><li>Уверенность в диагностике дисграфии и дислексии</li></ul>',
'logopedists', 'Диагностика письменной речи', NULL, 169.00, 1, 48);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 49
VALUES ('Олимпиада: Постановка звуков', 'olimpiada-postanovka-zvukov',
'Олимпиада о методах и приёмах постановки звуков в логопедической практике.',
'<p><strong>Олимпиада «Постановка звуков»</strong> — тестирование для логопедов, владеющих техниками постановки нарушенных звуков. Механическая постановка, постановка по подражанию, от опорного звука — проверьте, насколько уверенно вы применяете различные способы коррекции.</p><h3>Что вас ждёт</h3><p>10 вопросов о технике постановки звуков: способы постановки (по подражанию, механический, смешанный), подготовительный этап, артикуляционные упражнения для каждой группы звуков, использование зондов и зондозаменителей, последовательность работы над звуком.</p><h3>Кому подойдёт</h3><ul><li>Логопедам, работающим над коррекцией звукопроизношения</li><li>Начинающим логопедам, осваивающим постановку звуков</li><li>Специалистам частной логопедической практики</li><li>Логопедам, подтверждающим квалификацию</li></ul><h3>Преимущества участия</h3><ul><li><strong>Участие бесплатное</strong> — пройдите тест в удобное время</li><li>Практические вопросы по технике постановки звуков</li><li>Диплом всероссийской олимпиады для портфолио — 169 руб.</li><li>Проверка ключевой компетенции логопеда</li></ul>',
'logopedists', 'Постановка звуков', NULL, 169.00, 1, 49);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 50
VALUES ('Олимпиада: Автоматизация звуков', 'olimpiada-avtomatizatsiya-zvukov',
'Проверьте знания о приёмах и последовательности автоматизации поставленных звуков.',
'<p><strong>Олимпиада «Автоматизация звуков»</strong> — специализированное тестирование для логопедов, закрепляющих правильное звукопроизношение. Автоматизация — длительный и кропотливый этап, требующий от логопеда знания последовательности и разнообразных приёмов работы.</p><h3>Что вас ждёт</h3><p>10 вопросов об этапах автоматизации: закрепление звука в слогах, словах, фразах и связной речи, подбор речевого материала, игровые приёмы автоматизации, работа с чистоговорками и скороговорками, контроль за звукопроизношением в спонтанной речи.</p><h3>Кому подойдёт</h3><ul><li>Логопедам ДОУ и школьных логопунктов</li><li>Специалистам, работающим над закреплением звуков</li><li>Логопедам частной практики</li><li>Студентам логопедических специальностей</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное участие</strong> — без регистрационных сборов</li><li>Проверка методической грамотности в автоматизации звуков</li><li>Диплом I, II или III степени для портфолио — 169 руб.</li><li>Новые идеи для работы на этапе автоматизации</li></ul>',
'logopedists', 'Автоматизация звуков', NULL, 169.00, 1, 50);
