VALUES ('Олимпиада: Формирование лексико-грамматического строя', 'olimpiada-formirovanie-leksiko-grammaticheskogo-stroya',
'Олимпиада о методах развития лексики и грамматики у детей с речевыми нарушениями.',
'<p><strong>Олимпиада «Формирование лексико-грамматического строя»</strong> — тестирование для логопедов, развивающих у детей словарный запас и грамматические навыки. Лексика и грамматика — фундамент речи, и их формирование у детей с речевыми нарушениями требует системной и целенаправленной работы логопеда.</p><h3>Что вас ждёт</h3><p>10 вопросов о формировании лексики и грамматики: методы обогащения и активизации словаря, развитие словообразования и словоизменения, работа над предложно-падежными конструкциями, типичные аграмматизмы у детей с ОНР и приёмы их коррекции.</p><h3>Кому подойдёт</h3><ul><li>Логопедам, работающим с детьми с ОНР и ФФНР</li><li>Учителям-логопедам дошкольных учреждений</li><li>Дефектологам и коррекционным педагогам</li><li>Специалистам, повышающим квалификацию</li></ul><h3>Преимущества участия</h3><ul><li><strong>Бесплатное прохождение</strong> олимпиады онлайн</li><li>Практические вопросы по развитию лексики и грамматики</li><li>Диплом для аттестационного портфолио — 169 руб.</li><li>Систематизация подходов к формированию речи</li></ul>',
'logopedists', 'Формирование лексико-грамматического строя', NULL, 169.00, 1, 53);
SET @olympiad_id = LAST_INSERT_ID();


-- Олимпиада 54
VALUES ('Олимпиада: Развитие связной речи при ОНР', 'olimpiada-razvitie-svyaznoj-rechi-pri-onr',
'Проверьте знания о методах развития связной речи у детей с общим недоразвитием речи.',
'<p><strong>Олимпиада «Развитие связной речи при ОНР»</strong> — тестирование для логопедов, формирующих у детей навыки связного высказывания. Связная речь — высший уровень речевого развития, и её формирование у детей с ОНР является одной из главных задач коррекционной работы логопеда.</p><h3>Что вас ждёт</h3><p>10 вопросов о развитии связной речи: обучение пересказу с опорой на картинки, составление описательных и сюжетных рассказов, формирование диалогической речи, использование мнемотаблиц, поэтапная работа от фразы к тексту у детей с разными уровнями ОНР.</p><h3>Кому подойдёт</h3><ul><li>Логопедам логопедических групп и логопунктов</li><li>Учителям-логопедам, работающим с детьми с ОНР</li><li>Воспитателям коррекционных групп ДОУ</li><li>Логопедам, готовящим документы для аттестации</li></ul><h3>Преимущества участия</h3><ul><li><strong>Полностью бесплатное участие</strong> — без ограничений</li><li>Проверка знаний по развитию связной речи</li><li>Диплом I, II или III степени для портфолио — 169 руб.</li><li>Подтверждение профессиональных компетенций для аттестации</li></ul>',
'logopedists', 'Развитие связной речи при ОНР', NULL, 169.00, 1, 54);
SET @olympiad_id = LAST_INSERT_ID();


